<template><div class="page"><h2>仪表盘</h2><div class="grid grid-4"><div class="card" v-for="item in cards" :key="item.label"><div class="muted">{{item.label}}</div><div class="stat-num">{{item.value}}</div></div></div><div class="card" style="margin-top:16px"><h3>快速入口</h3><el-space wrap><el-button type="primary" @click="$router.push('/voices')">上传声音</el-button><el-button @click="$router.push('/tts')">开始 TTS</el-button><el-button @click="$router.push('/live')">进入直播面板</el-button><el-button @click="$router.push('/scripts')">管理脚本</el-button></el-space></div></div></template>
<script setup>import { ref,onMounted } from 'vue';import { getStatsOverview } from '../api/stats';const cards=ref([{label:'声音模型',value:0},{label:'TTS次数',value:0},{label:'脚本数量',value:0},{label:'直播场次',value:0}]);onMounted(async()=>{try{const d=await getStatsOverview();cards.value=[{label:'声音模型',value:d.voiceCount||0},{label:'TTS次数',value:d.ttsCount||0},{label:'脚本数量',value:d.scriptCount||0},{label:'直播场次',value:d.liveCount||0}]}catch{}})</script>
